import json
import base64
import os
import tempfile

class Substrato_941_cognitive_effort_controller:
    def __init__(self):
        self.seal = "2ca02aed5924f955bd4d366e661823edcc6536ce933628e20bb0b0b3dbb83f4c"
        self.files = {'cognitive_effort_controller.py': '', 'schema_941.yaml': ''}

    def canonize(self):
        temp_dir = tempfile.mkdtemp()
        for filename, b64_content in self.files.items():
            content = base64.b64decode(b64_content).decode("utf-8")
            path = os.path.join(temp_dir, filename)
            with open(path, "w") as f:
                f.write(content)

        report = {
            "Substrate": "941",
            "Status": "CANONIZED_PROVISIONAL",
            "Canonical_Seal": self.seal,
            "Files": list(self.files.keys())
        }

        report_path = os.path.join(temp_dir, "report.json")
        with open(report_path, "w") as f:
            json.dump(report, f, indent=2)

        return report_path
